-- Enums
DO $$ BEGIN CREATE TYPE public.app_role AS ENUM ('ADMIN','TREASURER','CLERK','VIEWER'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE public.allocation_type AS ENUM ('PERCENTAGE','FIXED'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE public.holder_type AS ENUM ('INDIVIDUAL','DEPARTMENT'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE public.imprest_status AS ENUM ('OPEN','CLOSED','RETIRED'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE public.member_status AS ENUM ('ACTIVE','INACTIVE','TRANSFERRED','DECEASED','DISFELLOWSHIPPED'); EXCEPTION WHEN duplicate_object THEN null; END $$;
DO $$ BEGIN CREATE TYPE public.payment_method AS ENUM ('CASH','CHEQUE','MOMO','BANK_TRANSFER','CARD'); EXCEPTION WHEN duplicate_object THEN null; END $$;

CREATE TABLE IF NOT EXISTS public.fund_groups (id serial PRIMARY KEY, name varchar NOT NULL, description text, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.funds (id serial PRIMARY KEY, name varchar NOT NULL, fund_group_id integer REFERENCES public.fund_groups(id), allocation_type public.allocation_type NOT NULL DEFAULT 'PERCENTAGE', local_percentage numeric DEFAULT 0, conference_percentage numeric DEFAULT 0, district_percentage numeric DEFAULT 0, is_member_tracked boolean DEFAULT false, is_active boolean DEFAULT true, requires_return boolean, return_frequency text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.fund_departments (id serial, fund_id integer REFERENCES public.funds(id), department_id integer, allocated_amount numeric, spent_amount numeric, created_at timestamptz);
CREATE TABLE IF NOT EXISTS public.sabbath_sessions (id serial PRIMARY KEY, date timestamptz NOT NULL, opened_at timestamptz, closed_at timestamptz, opened_by text, closed_by text, status varchar, notes text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.sabbath_accounts (id serial PRIMARY KEY, session_id integer REFERENCES public.sabbath_sessions(id), week_start date, week_end date, opened_at timestamptz, opened_by text, status varchar DEFAULT 'OPEN', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.bank_accounts (id serial PRIMARY KEY, name varchar NOT NULL, account_type varchar NOT NULL, bank_name varchar, account_number varchar, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.bank_transactions (id serial PRIMARY KEY, account_id integer REFERENCES public.bank_accounts(id), date timestamptz NOT NULL, amount numeric NOT NULL, description varchar, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.collections (id serial PRIMARY KEY, fund_id integer REFERENCES public.funds(id), member_id integer, date timestamptz NOT NULL, amount numeric NOT NULL, session_id integer REFERENCES public.sabbath_sessions(id), notes text, entered_by text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.transactions (id serial PRIMARY KEY, date timestamptz NOT NULL, amount numeric NOT NULL, type varchar NOT NULL, category varchar, notes text, entered_by text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.imprest_accounts (id serial PRIMARY KEY, name varchar NOT NULL, holder_type public.holder_type NOT NULL, description text, is_active boolean DEFAULT true, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.imprest_issues (id serial PRIMARY KEY, imprest_account_id integer REFERENCES public.imprest_accounts(id), issued_amount numeric NOT NULL, issue_date date NOT NULL, status public.imprest_status DEFAULT 'OPEN', purpose text, issued_by text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.imprest_expenses (id serial PRIMARY KEY, imprest_issue_id integer REFERENCES public.imprest_issues(id), fund_id integer, expense_date date NOT NULL, amount numeric NOT NULL, description varchar NOT NULL, receipt_no varchar, session_id integer, cheque_id bigint, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.cheques (id bigserial PRIMARY KEY, cheque_number varchar NOT NULL, payee varchar NOT NULL, amount numeric NOT NULL, bank_account varchar NOT NULL, issue_date date NOT NULL, due_date date NOT NULL, department_id bigint NOT NULL, expenses_id bigint, status varchar DEFAULT 'ISSUED', notes text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.profiles (id uuid PRIMARY KEY, full_name text NOT NULL DEFAULT '', email text, user_type text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_songs (id serial PRIMARY KEY, title varchar NOT NULL, composer varchar, lyrics text, notes text, choir_name varchar DEFAULT 'Main Choir', is_active boolean DEFAULT true, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_members (id serial PRIMARY KEY, member_id integer NOT NULL, voice_part varchar, choir_name varchar DEFAULT 'Main Choir', is_active boolean DEFAULT true, joined_at timestamptz DEFAULT now(), created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_rehearsals (id serial PRIMARY KEY, title varchar NOT NULL, rehearsal_date date NOT NULL, start_time time, end_time time, location varchar, notes text, choir_name varchar DEFAULT 'Main Choir', created_by uuid, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_announcements (id serial PRIMARY KEY, title varchar NOT NULL, body text NOT NULL, is_pinned boolean DEFAULT false, choir_name varchar DEFAULT 'Main Choir', created_by uuid, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_attendance (id serial PRIMARY KEY, rehearsal_id integer REFERENCES public.choir_rehearsals(id), member_id integer NOT NULL, status varchar DEFAULT 'present', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_setlist_items (id serial PRIMARY KEY, rehearsal_id integer REFERENCES public.choir_rehearsals(id), song_id integer REFERENCES public.choir_songs(id), sort_order integer DEFAULT 0, notes text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.choir_song_media (id serial PRIMARY KEY, song_id integer REFERENCES public.choir_songs(id), file_type text NOT NULL, file_name text NOT NULL, file_url text NOT NULL, voice_part text, mime_type text, file_size bigint, uploaded_by uuid, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.fund_returns (id serial PRIMARY KEY, fund_name varchar NOT NULL, return_date date NOT NULL, amount numeric NOT NULL, recipient varchar NOT NULL, payment_method public.payment_method NOT NULL, reference_number varchar, description text, document_url text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS public.payments (id serial PRIMARY KEY, payment_date date NOT NULL, amount numeric NOT NULL, payment_method public.payment_method NOT NULL, category varchar NOT NULL, vendor varchar NOT NULL, reference_number varchar, description text, document_url text, created_at timestamptz DEFAULT now());